-- ============================================================================
-- Migration 027: Agent type column + official IP ranges for preset bots
-- ============================================================================
--
-- 1. Adds a `type` column to distinguish platform presets from workspace-created
--    custom agents. Preset agents can only be created by the platform admin.
--    Custom agents belong to exactly one workspace and are deleted when that
--    workspace unsubscribes from them.
--
-- 2. Backfills `type = 'preset'` for the 25 agents seeded in migration 018.
--
-- 3. Replaces placeholder empty declared_ips ('{}') with the official, current
--    IP ranges published by each bot operator. Sources fetched 2026-04-23:
--
--    OpenAI   : https://openai.com/gptbot.json
--               https://openai.com/searchbot.json
--               https://openai.com/chatgpt-user.json
--    Google   : https://developers.google.com/search/apis/ipranges/googlebot.json
--               https://developers.google.com/search/apis/ipranges/special-crawlers.json
--               https://developers.google.com/search/apis/ipranges/user-triggered-fetchers.json
--    Microsoft: https://www.bing.com/toolbox/bingbot.json
--    Perplexity: https://www.perplexity.ai/perplexitybot.json
--               https://www.perplexity.ai/perplexity-user.json
--    Apple    : https://search.developer.apple.com/applebot.json
--    Mistral  : https://mistral.ai/mistralai-user-ips.json
--    Amazonbot: https://developer.amazon.com/amazonbot/searchbot-ip-addresses/
--
-- NOTE: Amazonbot IPs unavailable (connection refused). ClaudeBot family and
--       Meta-ExternalAgent have no official published IP JSON endpoint yet.
--
-- IMPORTANT: No production data exists. Safe to run.
-- ============================================================================


-- ============================================================================
-- 1. Add type column
-- ============================================================================

ALTER TABLE public.agents
  ADD COLUMN IF NOT EXISTS type TEXT NOT NULL DEFAULT 'custom'
    CHECK (type IN ('preset', 'custom'));

COMMENT ON COLUMN public.agents.type IS
  'preset = platform-maintained (admin-only creation, immutable by clients); '
  'custom = workspace-created (owned by one workspace, deleted on unsubscribe)';


-- ============================================================================
-- 2. Mark all 25 platform presets seeded in migration 018
-- ============================================================================

UPDATE public.agents
SET type = 'preset'
WHERE name IN (
  -- OpenAI
  'GPTBot', 'OAI-SearchBot', 'ChatGPT-User', 'OAI-SearchAgent',
  -- Anthropic
  'ClaudeBot', 'Claude-SearchBot', 'Claude-User', 'anthropic-ai',
  -- Google
  'Googlebot', 'Google-Extended', 'GoogleOther', 'Gemini-Deep-Research',
  'Google-CloudVertexBot',
  -- Microsoft
  'bingbot', 'BingPreview', 'AdIdxBot',
  -- Perplexity
  'PerplexityBot', 'Perplexity-User', 'Perplexity-Search',
  -- Amazon
  'Amazonbot',
  -- Apple
  'Applebot', 'Applebot-Extended',
  -- Meta
  'Meta-ExternalAgent',
  -- Mistral
  'MistralAI-User', 'MistralAI-SearchBot'
);


